__global__ void euclid(LatLong *d_locations, float *d_distances, int numRecords,float lat, float lng)
{
	int globalId = blockDim.x * ( gridDim.x * blockIdx.y + blockIdx.x ) + threadIdx.x; 
    LatLong *latLong = d_locations+globalId;
    if (globalId < numRecords) {
        float *dist=d_distances+globalId;
        *dist = (float)sqrt((lat-latLong->lat)*(lat-latLong->lat)+(lng-latLong->lng)*(lng-latLong->lng));
	}
}

int main(int argc, char* argv[])
{
	int    i=0;
	float lat, lng;
	int quiet=0,timing=0,platform=0,device=0;

    std::vector<Record> records;
	std::vector<LatLong> locations;
	char filename[100];
	int resultsCount=10;

    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int numRecords = loadData(filename,records,locations);
    if (resultsCount > numRecords) resultsCount = numRecords;

    float *distances;

    LatLong *d_locations;
    float *d_distances;

    cl_context context = cl_init_context(platform, device, quiet);
    cl_device_id device_id;
    cl_int status;
    status = clGetContextInfo(context, CL_CONTEXT_DEVICES, sizeof(device_id), &device_id, NULL);
    cl_errChk(status, "Getting device from context", true);

    cl_ulong maxGridX = 0;
    size_t maxThreadsPerBlock = 0;
    clGetDeviceInfo(device_id, CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(maxThreadsPerBlock), &maxThreadsPerBlock, NULL);

    cl_ulong freeDeviceMemory = 0;
    cl_ulong totalDeviceMemory = 0;
    clGetDeviceInfo(device_id, CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(totalDeviceMemory), &totalDeviceMemory, NULL);
    freeDeviceMemory = totalDeviceMemory; 

    unsigned long usableDeviceMemory = freeDeviceMemory * 85 / 100; 
    unsigned long maxThreads = usableDeviceMemory / 12; 

    if ( numRecords > maxThreads )
    {
        fprintf( stderr, "Error: Input too large.\n" );
        exit( 1 );
    }

    unsigned long threadsPerBlock = min( (unsigned long)maxThreadsPerBlock, (unsigned long)DEFAULT_THREADS_PER_BLOCK );
    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock );

    cl_ulong maxGridDim = 0;
    clGetDeviceInfo(device_id, CL_DEVICE_MAX_WORK_ITEM_DIMENSIONS, sizeof(maxGridDim), &maxGridDim, NULL);

    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    size_t global_size[2];
    global_size[0] = threadsPerBlock * gridX;
    global_size[1] = threadsPerBlock * gridY;

    size_t local_size[2];
    local_size[0] = threadsPerBlock;
    local_size[1] = threadsPerBlock;

    if ( DEBUG )
    {
        print( totalDeviceMemory ); 
        print( freeDeviceMemory );
        print( usableDeviceMemory );
        print( maxGridX ); 
        print( maxThreadsPerBlock ); 
        print( threadsPerBlock );
        print( maxThreads );
        print( blocks ); 
        print( gridY );
        print( gridX );
    }

    distances = (float *)malloc(sizeof(float) * numRecords);

    cl_mem d_locations_mem = cl_allocBuffer(sizeof(LatLong) * numRecords, CL_MEM_READ_WRITE);
    cl_mem d_distances_mem = cl_allocBuffer(sizeof(float) * numRecords, CL_MEM_READ_WRITE);

    cl_copyBufferToDevice(d_locations_mem, &locations[0], sizeof(LatLong) * numRecords, CL_TRUE);

#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

    cl_program program = cl_compileProgram("translated_0.cl", "", false);
    cl_kernel kernel = cl_createKernel(program, "euclid");

    cl_setKernelArg(kernel, 0, sizeof(cl_mem), &d_locations_mem);
    cl_setKernelArg(kernel, 1, sizeof(cl_mem), &d_distances_mem);
    cl_setKernelArg(kernel, 2, sizeof(int), &numRecords);
    cl_setKernelArg(kernel, 3, sizeof(float), &lat);
    cl_setKernelArg(kernel, 4, sizeof(float), &lng);

    status = clEnqueueTask(cl_getCommandQueue(), kernel, 0, NULL, NULL);
    cl_errChk(status, "Enqueue task", true);

    cl_sync();

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
